package com.samudhra.certificates.entity;
import jakarta.persistence.*; import java.util.*;
@Entity @Table(name="templates", indexes={@Index(columnList="organization_id"),@Index(columnList="status")}) public class Template extends BaseEntity {
  @Column(nullable=false) private String name; private String category; private String description; private String orientation; private String paperSize; @Column(nullable=false) private String status="DRAFT"; @Lob @Column(columnDefinition="LONGTEXT") private String backgroundJson;
  @ManyToOne(fetch=FetchType.LAZY, optional=false) private Organization organization; @OneToMany(mappedBy="template", cascade=CascadeType.ALL, orphanRemoval=true) @OrderBy("zIndex ASC") private List<TemplateElement> elements=new ArrayList<>();
  public String getName(){return name;} public void setName(String v){name=v;} public String getCategory(){return category;} public void setCategory(String v){category=v;} public String getDescription(){return description;} public void setDescription(String v){description=v;} public String getOrientation(){return orientation;} public void setOrientation(String v){orientation=v;} public String getPaperSize(){return paperSize;} public void setPaperSize(String v){paperSize=v;} public String getStatus(){return status;} public void setStatus(String v){status=v;} public String getBackgroundJson(){return backgroundJson;} public void setBackgroundJson(String v){backgroundJson=v;} public Organization getOrganization(){return organization;} public void setOrganization(Organization v){organization=v;} public List<TemplateElement> getElements(){return elements;} public void setElements(List<TemplateElement> v){elements=v;}
}
